import { useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";
import { 
  Mountain, 
  User, 
  Mail, 
  Lock, 
  Eye, 
  EyeOff, 
  MapPin, 
  Shield,
  ArrowLeft,
  CheckCircle,
  Phone,
  Map,
  Briefcase,
  Award,
  Globe,
  CreditCard,
  FileText
} from "lucide-react";

const Register = () => {
  const [formData, setFormData] = useState({
    full_name: "",
    email: "",
    password: "",
    confirmPassword: "",
    phone: "",
    user_type: "",
    // Additional fields based on user type
    nationality: "",
    address: "",
    pan_number: "",
    license_no: "",
    experience_years: ""
  });

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [passwordStrength, setPasswordStrength] = useState(0);
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Calculate password strength
    if (name === 'password') {
      let strength = 0;
      if (value.length >= 8) strength += 25;
      if (/[A-Z]/.test(value)) strength += 25;
      if (/[0-9]/.test(value)) strength += 25;
      if (/[^A-Za-z0-9]/.test(value)) strength += 25;
      setPasswordStrength(strength);
    }
  };

  const handleUserTypeChange = (user_type) => {
    setFormData(prev => ({
      ...prev,
      user_type,
      // Reset additional fields when changing user type
      nationality: user_type === "tourist" ? prev.nationality : "",
      address: (user_type === "host" || user_type === "guide") ? prev.address : "",
      pan_number: user_type === "host" ? prev.pan_number : "",
      license_no: user_type === "guide" ? prev.license_no : "",
      experience_years: user_type === "guide" ? prev.experience_years : ""
    }));
  };

  const getStrengthColor = (strength) => {
    if (strength <= 25) return "bg-red-500";
    if (strength <= 50) return "bg-orange-500";
    if (strength <= 75) return "bg-yellow-500";
    return "bg-green-500";
  };

  const getStrengthText = (strength) => {
    if (strength <= 25) return "Weak";
    if (strength <= 50) return "Fair";
    if (strength <= 75) return "Good";
    return "Strong";
  };

  const validatePhone = (phone) => {
    const phoneRegex = /^[0-9]{10}$/;
    return phoneRegex.test(phone);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    // Validation
    if (!formData.phone || !validatePhone(formData.phone)) {
      setError("Please enter a valid 10-digit phone number");
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    if (formData.password.length < 6) {
      setError("Password must be at least 6 characters long");
      return;
    }

    if (!formData.user_type) {
      setError("Please select a user type");
      return;
    }

    // Additional validations based on user type
    if (formData.user_type === "tourist" && !formData.nationality) {
      setError("Nationality is required for tourists");
      return;
    }

    if (formData.user_type === "host") {
      if (!formData.address) {
        setError("Address is required for hosts");
        return;
      }
      if (!formData.pan_number) {
        setError("PAN number is required for hosts");
        return;
      }
    }

    if (formData.user_type === "guide") {
      if (!formData.license_no) {
        setError("License number is required for guides");
        return;
      }
      if (!formData.experience_years || formData.experience_years < 0) {
        setError("Please enter valid experience years");
        return;
      }
      if (!formData.address) {
        setError("Address is required for guides");
        return;
      }
    }

    setIsLoading(true);

    try {
      // Prepare data based on user type
      let dataToSend = {
        full_name: formData.full_name,
        email: formData.email,
        password: formData.password,
        phone: formData.phone,
        user_type: formData.user_type
      };

      // Add additional fields based on user type
      if (formData.user_type === "tourist") {
        dataToSend.nationality = formData.nationality;
      } else if (formData.user_type === "host") {
        dataToSend.address = formData.address;
        dataToSend.pan_number = formData.pan_number;
      } else if (formData.user_type === "guide") {
        dataToSend.license_no = formData.license_no;
        dataToSend.experience_years = parseInt(formData.experience_years);
        dataToSend.address = formData.address;
      }

      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        dataToSend
      );

      if (res.data.token) localStorage.setItem("token", res.data.token);
      if (res.data.refreshToken) localStorage.setItem("refreshToken", res.data.refreshToken);
      if (res.data.user) localStorage.setItem("user", JSON.stringify(res.data.user));
      setSuccess("Account created successfully! Redirecting to login...");
      
      // Redirect to login after 2 seconds
      setTimeout(() => {
        navigate("/login");
      }, 2000);
      
    } catch (err) {
      setError(err.response?.data?.message || "Registration failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const userTypeInfo = {
    tourist: {
      title: "Tourist",
      icon: "👨‍🦱",
      description: "Explore Nepal's hidden trails and book unique experiences",
      color: "from-blue-100 to-blue-50",
      borderColor: "border-blue-200",
      bgColor: "bg-blue-100",
      textColor: "text-blue-600"
    },
    host: {
      title: "Host",
      icon: "🏠",
      description: "Share your local knowledge and host travelers",
      color: "from-emerald-100 to-emerald-50",
      borderColor: "border-emerald-200",
      bgColor: "bg-emerald-100",
      textColor: "text-emerald-600"
    },
    guide: {
      title: "Guide",
      icon: "🧭",
      description: "Guide adventurers through Nepal's beautiful landscapes",
      color: "from-purple-100 to-purple-50",
      borderColor: "border-purple-200",
      bgColor: "bg-purple-100",
      textColor: "text-purple-600"
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-50 via-white to-cyan-50 flex items-center justify-center p-4">
      {/* Background decorative elements */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute top-20 left-10 w-80 h-80 bg-amber-100 rounded-full mix-blend-multiply filter blur-xl opacity-60 animate-blob"></div>
        <div className="absolute top-20 right-10 w-80 h-80 bg-cyan-100 rounded-full mix-blend-multiply filter blur-xl opacity-60 animate-blob animation-delay-2000"></div>
        <div className="absolute -bottom-10 left-1/3 w-80 h-80 bg-emerald-100 rounded-full mix-blend-multiply filter blur-xl opacity-60 animate-blob animation-delay-4000"></div>
      </div>

      <div className="relative z-10 w-full max-w-6xl">
        {/* Back to Login */}
        <div className="mb-6">
          <Link
            to="/login"
            className="inline-flex items-center text-blue-600 hover:text-blue-800 font-medium group"
          >
            <ArrowLeft className="h-4 w-4 mr-2 transform group-hover:-translate-x-1 transition-transform duration-300" />
            Back to Login
          </Link>
        </div>

        <div className="bg-white/90 backdrop-blur-lg rounded-2xl shadow-2xl overflow-hidden border border-gray-200">
          <div className="md:flex">
            {/* Left Side - Brand & Info */}
            <div className="md:w-2/5 bg-gradient-to-br from-blue-700 to-emerald-700 p-8 text-white">
              <div className="h-full flex flex-col justify-between">
                <div>
                  <div className="flex items-center mb-6">
                    <Mountain className="h-12 w-12 mr-3" />
                    <div>
                      <h1 className="text-3xl font-bold tracking-wider">OffTrailNepal</h1>
                      <p className="text-blue-200 text-sm">Join the Adventure</p>
                    </div>
                  </div>
                  
                  <div className="mt-8">
                    <h2 className="text-xl font-semibold mb-4">Start Your Journey</h2>
                    <div className="space-y-4">
                      {Object.entries(userTypeInfo).map(([type, info]) => (
                        <div key={type} className="flex items-start">
                          <CheckCircle className="h-5 w-5 text-green-300 mr-3 mt-0.5 flex-shrink-0" />
                          <div>
                            <h3 className="font-medium">{info.title}</h3>
                            <p className="text-blue-200 text-sm">{info.description}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <div className="mt-8">
                  <div className="flex items-start">
                    <MapPin className="h-5 w-5 text-amber-300 mr-2 mt-0.5 flex-shrink-0" />
                    <p className="text-blue-100 text-sm">
                      "The journey of a thousand miles begins with a single step. Take yours today with OffTrailNepal."
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* Right Side - Registration Form */}
            <div className="md:w-3/5 p-8">
              <div className="max-w-2xl mx-auto">
                <div className="text-center mb-8">
                  <h2 className="text-2xl font-bold text-gray-800 mb-2">Create Your Account</h2>
                  <p className="text-gray-600">Join our community of explorers and locals</p>
                </div>

                {error && (
                  <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl">
                    <p className="text-red-600 text-sm flex items-center">
                      <svg className="w-4 h-4 mr-2" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                      </svg>
                      {error}
                    </p>
                  </div>
                )}

                {success && (
                  <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-xl">
                    <p className="text-green-600 text-sm flex items-center">
                      <CheckCircle className="w-4 h-4 mr-2" />
                      {success}
                    </p>
                  </div>
                )}

                <form onSubmit={handleSubmit}>
                  {/* Basic Information */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                    {/* Full Name */}
                    <div>
                      <label className="block text-gray-700 text-sm font-medium mb-2">
                        Full Name *
                      </label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <User className="h-5 w-5 text-gray-400" />
                        </div>
                        <input
                          type="text"
                          name="full_name"
                          value={formData.full_name}
                          onChange={handleChange}
                          className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300"
                          placeholder="John Doe"
                          required
                        />
                      </div>
                    </div>

                    {/* Email */}
                    <div>
                      <label className="block text-gray-700 text-sm font-medium mb-2">
                        Email Address *
                      </label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <Mail className="h-5 w-5 text-gray-400" />
                        </div>
                        <input
                          type="email"
                          name="email"
                          value={formData.email}
                          onChange={handleChange}
                          className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300"
                          placeholder="your.email@example.com"
                          required
                        />
                      </div>
                    </div>

                    {/* Phone Number */}
                    <div>
                      <label className="block text-gray-700 text-sm font-medium mb-2">
                        Phone Number *
                      </label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <Phone className="h-5 w-5 text-gray-400" />
                        </div>
                        <input
                          type="tel"
                          name="phone"
                          value={formData.phone}
                          onChange={handleChange}
                          className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300"
                          placeholder="98XXXXXXXX"
                          required
                          maxLength="10"
                        />
                      </div>
                      <p className="text-xs text-gray-500 mt-1">10-digit Nepal phone number</p>
                    </div>
                  </div>

                  {/* Password Section */}
                  <div className="mb-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      {/* Password */}
                      <div>
                        <label className="block text-gray-700 text-sm font-medium mb-2">
                          Password *
                        </label>
                        <div className="relative">
                          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <Lock className="h-5 w-5 text-gray-400" />
                          </div>
                          <input
                            type={showPassword ? "text" : "password"}
                            name="password"
                            value={formData.password}
                            onChange={handleChange}
                            className="w-full pl-10 pr-12 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300"
                            placeholder="Create a strong password"
                            required
                          />
                          <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="absolute inset-y-0 right-0 pr-3 flex items-center"
                          >
                            {showPassword ? (
                              <EyeOff className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                            ) : (
                              <Eye className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                            )}
                          </button>
                        </div>
                      </div>

                      {/* Confirm Password */}
                      <div>
                        <label className="block text-gray-700 text-sm font-medium mb-2">
                          Confirm Password *
                        </label>
                        <div className="relative">
                          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <Lock className="h-5 w-5 text-gray-400" />
                          </div>
                          <input
                            type={showConfirmPassword ? "text" : "password"}
                            name="confirmPassword"
                            value={formData.confirmPassword}
                            onChange={handleChange}
                            className="w-full pl-10 pr-12 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300"
                            placeholder="Confirm your password"
                            required
                          />
                          <button
                            type="button"
                            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                            className="absolute inset-y-0 right-0 pr-3 flex items-center"
                          >
                            {showConfirmPassword ? (
                              <EyeOff className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                            ) : (
                              <Eye className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                            )}
                          </button>
                        </div>
                      </div>
                    </div>
                    
                    {/* Password Strength Meter */}
                    {formData.password && (
                      <div className="mt-4 p-4 bg-gray-50 rounded-xl">
                        <div className="flex justify-between text-sm mb-2">
                          <span>Password strength:</span>
                          <span className={`font-medium ${
                            passwordStrength <= 25 ? "text-red-600" :
                            passwordStrength <= 50 ? "text-orange-600" :
                            passwordStrength <= 75 ? "text-yellow-600" : "text-green-600"
                          }`}>
                            {getStrengthText(passwordStrength)}
                          </span>
                        </div>
                        <div className="h-2 bg-gray-200 rounded-full overflow-hidden">
                          <div 
                            className={`h-full ${getStrengthColor(passwordStrength)} transition-all duration-300`}
                            style={{ width: `${passwordStrength}%` }}
                          ></div>
                        </div>
                        <ul className="mt-3 text-sm text-gray-600 grid grid-cols-2 gap-2">
                          <li className={`flex items-center ${formData.password.length >= 8 ? 'text-green-600' : ''}`}>
                            <CheckCircle className={`h-4 w-4 mr-2 ${formData.password.length >= 8 ? 'text-green-600' : 'text-gray-400'}`} />
                            At least 8 characters
                          </li>
                          <li className={`flex items-center ${/[A-Z]/.test(formData.password) ? 'text-green-600' : ''}`}>
                            <CheckCircle className={`h-4 w-4 mr-2 ${/[A-Z]/.test(formData.password) ? 'text-green-600' : 'text-gray-400'}`} />
                            Uppercase letter
                          </li>
                          <li className={`flex items-center ${/[0-9]/.test(formData.password) ? 'text-green-600' : ''}`}>
                            <CheckCircle className={`h-4 w-4 mr-2 ${/[0-9]/.test(formData.password) ? 'text-green-600' : 'text-gray-400'}`} />
                            Number
                          </li>
                          <li className={`flex items-center ${/[^A-Za-z0-9]/.test(formData.password) ? 'text-green-600' : ''}`}>
                            <CheckCircle className={`h-4 w-4 mr-2 ${/[^A-Za-z0-9]/.test(formData.password) ? 'text-green-600' : 'text-gray-400'}`} />
                            Special character
                          </li>
                        </ul>
                      </div>
                    )}
                  </div>

                  {/* User Type Selection */}
                  <div className="mb-8">
                    <label className="block text-gray-700 text-sm font-medium mb-4">
                      I want to join as a *
                    </label>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      {Object.entries(userTypeInfo).map(([type, info]) => (
                        <div
                          key={type}
                          className={`relative border-2 rounded-xl p-4 cursor-pointer transition-all duration-300 ${
                            formData.user_type === type
                              ? `border-blue-500 ${info.color}`
                              : 'border-gray-200 hover:border-gray-300'
                          }`}
                          onClick={() => handleUserTypeChange(type)}
                        >
                          <input
                            type="radio"
                            name="user_type"
                            value={type}
                            checked={formData.user_type === type}
                            onChange={() => {}}
                            className="sr-only"
                          />
                          <div className="text-center">
                            <div className={`inline-flex items-center justify-center w-12 h-12 rounded-full mb-3 ${
                              formData.user_type === type ? info.bgColor : 'bg-gray-100'
                            }`}>
                              <span className="text-xl">{info.icon}</span>
                            </div>
                            <h3 className="font-medium text-gray-900">{info.title}</h3>
                            <p className="text-xs text-gray-500 mt-1">{info.description}</p>
                          </div>
                          {formData.user_type === type && (
                            <div className="absolute top-3 right-3">
                              <CheckCircle className="h-5 w-5 text-blue-500" />
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Conditional Fields Based on User Type */}
                  {formData.user_type === "tourist" && (
                    <div className="mb-6 bg-blue-50 p-6 rounded-xl border border-blue-100">
                      <div className="flex items-center mb-4">
                        <Globe className="h-5 w-5 text-blue-600 mr-2" />
                        <h3 className="font-medium text-blue-800">Tourist Information</h3>
                      </div>
                      <div>
                        <label className="block text-gray-700 text-sm font-medium mb-2">
                          Nationality *
                        </label>
                        <div className="relative">
                          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <Globe className="h-5 w-5 text-gray-400" />
                          </div>
                          <input
                            type="text"
                            name="nationality"
                            value={formData.nationality}
                            onChange={handleChange}
                            className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300"
                            placeholder="e.g., American, British, Indian, etc."
                            required
                          />
                        </div>
                        <p className="text-xs text-gray-500 mt-1">
                          This helps us provide relevant travel information
                        </p>
                      </div>
                    </div>
                  )}

                  {formData.user_type === "host" && (
                    <div className="mb-6 bg-emerald-50 p-6 rounded-xl border border-emerald-100">
                      <div className="flex items-center mb-4">
                        <Map className="h-5 w-5 text-emerald-600 mr-2" />
                        <h3 className="font-medium text-emerald-800">Host Information</h3>
                      </div>
                      <div className="space-y-4">
                        <div>
                          <label className="block text-gray-700 text-sm font-medium mb-2">
                            Address *
                          </label>
                          <textarea
                            name="address"
                            value={formData.address}
                            onChange={handleChange}
                            className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all duration-300"
                            placeholder="Enter your full address including city and district"
                            rows="3"
                            required
                          />
                          <p className="text-xs text-gray-500 mt-1">
                            This will be shown to tourists looking for accommodation
                          </p>
                        </div>
                        <div>
                          <label className="block text-gray-700 text-sm font-medium mb-2">
                            PAN Number *
                          </label>
                          <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                              <CreditCard className="h-5 w-5 text-gray-400" />
                            </div>
                            <input
                              type="text"
                              name="pan_number"
                              value={formData.pan_number}
                              onChange={handleChange}
                              className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all duration-300"
                              placeholder="Enter your PAN number"
                              required
                            />
                          </div>
                          <p className="text-xs text-gray-500 mt-1">
                            Required for tax and payment purposes
                          </p>
                        </div>
                      </div>
                    </div>
                  )}

                  {formData.user_type === "guide" && (
                    <div className="mb-6 bg-purple-50 p-6 rounded-xl border border-purple-100">
                      <div className="flex items-center mb-4">
                        <Briefcase className="h-5 w-5 text-purple-600 mr-2" />
                        <h3 className="font-medium text-purple-800">Guide Information</h3>
                      </div>
                      <div className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                          <div>
                            <label className="block text-gray-700 text-sm font-medium mb-2">
                              Citizenship Number *
                            </label>
                            <div className="relative">
                              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <FileText className="h-5 w-5 text-gray-400" />
                              </div>
                              <input
                                type="text"
                                name="license_no"
                                value={formData.license_no}
                                onChange={handleChange}
                                className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-purple-500 transition-all duration-300"
                                placeholder="Enter citizenship number"
                                required
                              />
                            </div>
                            <p className="text-xs text-gray-500 mt-1">
                              Your official citizenship number
                            </p>
                          </div>
                          <div>
                            <label className="block text-gray-700 text-sm font-medium mb-2">
                              Years of Experience *
                            </label>
                            <div className="relative">
                              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Award className="h-5 w-5 text-gray-400" />
                              </div>
                              <input
                                type="number"
                                name="experience_years"
                                value={formData.experience_years}
                                onChange={handleChange}
                                className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-purple-500 transition-all duration-300"
                                placeholder="5"
                                min="0"
                                required
                              />
                            </div>
                          </div>
                        </div>
                        <div>
                          <label className="block text-gray-700 text-sm font-medium mb-2">
                            Address *
                          </label>
                          <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                              <Map className="h-5 w-5 text-gray-400" />
                            </div>
                            <textarea
                              name="address"
                              value={formData.address}
                              onChange={handleChange}
                              className="w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-purple-500 transition-all duration-300"
                              placeholder="Enter your full address"
                              rows="2"
                              required
                            />
                          </div>
                          <p className="text-xs text-gray-500 mt-1">
                            Your current residential address
                          </p>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* Terms and Conditions */}
                  <div className="mb-8">
                    <label className="flex items-start">
                      <input
                        type="checkbox"
                        required
                        className="h-4 w-4 text-blue-600 rounded focus:ring-blue-500 border-gray-300 mt-1"
                      />
                      <span className="ml-2 text-sm text-gray-600">
                        I agree to the{" "}
                        <Link to="/terms" className="text-blue-600 hover:text-blue-800">
                          Terms of Service
                        </Link>{" "}
                        and{" "}
                        <Link to="/privacy" className="text-blue-600 hover:text-blue-800">
                          Privacy Policy
                        </Link>{" "}
                        of OffTrailNepal. I confirm that all information provided is accurate.
                      </span>
                    </label>
                  </div>

                  {/* Submit Button */}
                  <button
                    type="submit"
                    disabled={isLoading}
                    className="w-full py-3 px-4 bg-gradient-to-r from-blue-600 to-emerald-600 hover:from-blue-700 hover:to-emerald-700 text-white font-semibold rounded-xl shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none disabled:hover:shadow-lg"
                  >
                    {isLoading ? (
                      <div className="flex items-center justify-center">
                        <div className="w-5 h-5 border-t-2 border-white rounded-full animate-spin mr-2"></div>
                        Creating Account...
                      </div>
                    ) : (
                      "Create My Account"
                    )}
                  </button>
                </form>

                {/* Already have account */}
                <div className="mt-8 text-center">
                  <p className="text-gray-600">
                    Already have an account?{" "}
                    <Link
                      to="/login"
                      className="font-semibold text-blue-600 hover:text-blue-800 transition-colors duration-300"
                    >
                      Sign In
                    </Link>
                  </p>
                </div>

                {/* Security Note */}
                <div className="mt-8 pt-6 border-t border-gray-200">
                  <div className="flex items-center justify-center text-gray-500 text-sm">
                    <Shield className="h-4 w-4 mr-2" />
                    <span>Your information is secured with 256-bit encryption</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="mt-6 text-center text-gray-500 text-sm">
          <p>© {new Date().getFullYear()} OffTrailNepal. All rights reserved.</p>
          <p className="mt-1">Join our community of 10,000+ explorers and locals</p>
        </div>
      </div>

      {/* Add CSS for blob animation */}
      <style>{`
        @keyframes blob {
          0% { transform: translate(0px, 0px) scale(1); }
          33% { transform: translate(30px, -50px) scale(1.1); }
          66% { transform: translate(-20px, 20px) scale(0.9); }
          100% { transform: translate(0px, 0px) scale(1); }
        }
        .animate-blob {
          animation: blob 7s infinite;
        }
        .animation-delay-2000 {
          animation-delay: 2s;
        }
        .animation-delay-4000 {
          animation-delay: 4s;
        }
      `}</style>
    </div>
  );
};

export default Register;
